// UploadBills.jsx — CLEAN VERSION (Only Upload Section)
// (No history table, no download button, no delete, no preview)

import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const API = process.env.REACT_APP_API_BASE;

export default function UploadBills({ employee }) {
  const navigate = useNavigate();
  const [files, setFiles] = useState(null);

  // Upload bills
  const handleUpload = async () => {
    if (!files) return alert("Please select a file");

    const formData = new FormData();
    for (let f of files) formData.append("bills", f);
    formData.append("empId", employee.empld);

    try {
      await axios.post(`${API}/bills/upload`, formData);
      alert("Bills uploaded successfully!");
      setFiles(null);
    } catch (err) {
      alert("Upload failed");
    }
  };

  const green = "#0f9d58";
  const light = "#e8f7ee";

  return (
    <div
      style={{
        background: light,
        minHeight: "100vh",
        padding: "25px",
        display: "flex",
        justifyContent: "center",
      }}
    >
      {/* MAIN CARD */}
      <div
        style={{
          width: "90%",
          maxWidth: "750px",
          background: "#fff",
          padding: "22px",
          borderRadius: "18px",
          boxShadow: "0px 4px 12px rgba(0,0,0,0.1)",
        }}
      >
        {/* HEADER */}
        <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
          <button
            onClick={() => navigate(-1)}
            style={{
              background: light,
              border: "none",
              padding: "10px 14px",
              borderRadius: "12px",
              fontSize: "18px",
              cursor: "pointer",
            }}
          >
            ←
          </button>

          <h2 style={{ color: green, margin: 0 }}>Upload Bills</h2>
        </div>

        <p style={{ marginTop: "10px", color: "#555" }}>
          Employee: {employee?.name} • {employee?.empld}
        </p>

        {/* UPLOAD AREA */}
        <div
          style={{
            background: light,
            padding: "18px",
            borderRadius: "14px",
            marginTop: "18px",
          }}
        >
          <label style={{ fontWeight: "600", fontSize: "15px" }}>
            Choose Bills
          </label>

          {/* File Picker + Upload Button (Under It) */}
          <input
            type="file"
            multiple
            onChange={(e) => setFiles(e.target.files)}
            style={{
              width: "100%",
              padding: "10px",
              marginTop: "10px",
              borderRadius: "10px",
            }}
          />

          {/* Upload Button BELOW */}
          <button
            onClick={handleUpload}
            style={{
              marginTop: "15px",
              width: "100%",
              background: green,
              color: "white",
              border: "none",
              padding: "12px 0",
              borderRadius: "10px",
              cursor: "pointer",
              fontSize: "16px",
            }}
          >
            Upload
          </button>
        </div>
      </div>
    </div>
  );
}
